fn xii_emit_gen_override(horizon_id: u8, target: u8, payload: *u8, size: u16) -> i32 @export {
    /* Domain sentinel: horizon ids 0..143 and targets 0..6 are the ONLY cells
     * that xii_emit_gen_produce can serve.  Reject dead registrations immediately
     * so no cap slot is consumed for a (horizon_id, target) pair that can never
     * resolve — making the sentinel contract consistent with produce's own guards. */
    if (horizon_id as u32) >= 144u32 { return -1i32 }
    if (target as u32) >= 7u32 { return -1i32 }
    if XEG_OVERRIDE_USED >= XEG_OVERRIDE_CAP { return -1i32 }
    if (size as u32) > 256u32 { return -1i32 }
    let key_off : u32 = XEG_OVERRIDE_USED * 4u32
    XEG_OVERRIDE_KEYS[key_off]        = horizon_id
    XEG_OVERRIDE_KEYS[key_off + 1u32] = target
    XEG_OVERRIDE_KEYS[key_off + 2u32] = (size as u32 & 0xFFu32) as u8
    XEG_OVERRIDE_KEYS[key_off + 3u32] = ((size as u32 >> 8u32) & 0xFFu32) as u8
    let pay_off : u32 = XEG_OVERRIDE_USED * 256u32
    let mut i : u32 = 0u32
    while i < (size as u32) {
        XEG_OVERRIDE_PAYLOAD[pay_off + i] = payload[i as u64]
        i = i + 1u32
    }
    XEG_OVERRIDE_USED = XEG_OVERRIDE_USED + 1u32
    return 0i32
}

fn _sha256_prefix_then_payload(prefix: *u8, prefix_len: u32, payload: *u8, payload_size: u32, out_32: *u8) -> i32 {
    /* Overflow-safe form (subtraction): a + b > CAP wraps on large b;           */
    /* b > CAP - a does not (CAP - a is always <= CAP, no u32 underflow because  */
    /* we reject prefix_len >= CAP first).  XEG_MHASH_SCRATCH = 4096 bytes.      */
    if prefix_len > 4096u32 { return -1i32 }
    if payload_size > 4096u32 - prefix_len { return -1i32 }
    let mut i : u32 = 0u32
    while i < prefix_len {
        XEG_MHASH_SCRATCH[i] = prefix[i as u64]
        i = i + 1u32
    }
    let mut j : u32 = 0u32
    while j < payload_size {
        XEG_MHASH_SCRATCH[prefix_len + j] = payload[j as u64]
        j = j + 1u32
    }
    sha256_oneshot(&XEG_MHASH_SCRATCH as *u8, (prefix_len + payload_size) as u64, out_32)
    return 0i32
}

/* 1023 — xii-export-bounds: xii_emit_gen @export sentinel contract.
 *
 * NEGATIVE ARM (proves fixes fire):
 *   (a) cell_mhash with payload_size = 0xFFFFFFFE must return -1 (subtraction-form
 *       guard fires); under the prior addition form, 4 + 0xFFFFFFFE wrapped to 2,
 *       2 > 4096 was false, and ~4 billion writes would clobber the BSS.
 *   (b) xii_emit_gen_override with horizon_id >= 144 must return -1 (domain gate
 *       fires); the old code stored the dead entry and returned 0, consuming a cap
 *       slot for an override that could never be served.
 *   (c) xii_emit_gen_override with target >= 7 must return -1 (domain gate fires).
 *
 * POSITIVE ARM (proves fixes don't break valid paths):
 *   (d) cell_mhash with a small valid payload succeeds (returns 0) and writes a
 *       deterministic 32-byte SHA-256 hash.
 *   (e) override with valid (horizon_id < 144, target < 7) still returns 0 and
 *       xeg_override_index resolves it (not the no-override sentinel).
 *
 * 99 = all arms hold.
 */
module corpus_1023

extern @abi(c-msvc-x64) fn xii_emit_gen_cell_mhash(horizon_id: u32, target: u32, size: u32, payload_ptr: *u8, out_32: *u8) -> i32 from "xii_emit_gen.iii"
extern @abi(c-msvc-x64) fn xii_emit_gen_override(horizon_id: u8, target: u8, payload: *u8, size: u16) -> i32 from "xii_emit_gen.iii"
extern @abi(c-msvc-x64) fn xeg_override_index(horizon_id: u8, target: u8) -> u32 from "xii_emit_gen.iii"

var MHASH_OUT : [u8; 32]
var SMALL_PAY : [u8; 8]
var DEAD_PAY  : [u8; 4]

fn main() -> u64 {
    /* (a) NEGATIVE: cell_mhash with size = 0xFFFFFFFE must return -1.
     *     Under the old addition form: 4 + 0xFFFFFFFE = 2, guard false -> OOB.
     *     Under the new subtraction form: 0xFFFFFFFE > 4096 - 4 = 4092 -> true -> -1. */
    let huge_size : u32 = 0xFFFFFFFEu32
    if xii_emit_gen_cell_mhash(50u32, 1u32, huge_size, &DEAD_PAY as *u8, &MHASH_OUT as *u8) != -1i32 { return 1u64 }

    /* (b) NEGATIVE: override with horizon_id = 200 (>= 144) must return -1. */
    DEAD_PAY[0] = 0xAAu8
    DEAD_PAY[1] = 0xBBu8
    DEAD_PAY[2] = 0xCCu8
    DEAD_PAY[3] = 0xDDu8
    if xii_emit_gen_override(200u8, 1u8, &DEAD_PAY as *u8, 4u16) != -1i32 { return 2u64 }
    /* confirm dead entry was NOT stored */
    if xeg_override_index(200u8, 1u8) != 0xFFFFFFFFu32 { return 3u64 }

    /* (c) NEGATIVE: override with target = 7 (>= 7) must return -1. */
    if xii_emit_gen_override(50u8, 7u8, &DEAD_PAY as *u8, 4u16) != -1i32 { return 4u64 }
    if xeg_override_index(50u8, 7u8) != 0xFFFFFFFFu32 { return 5u64 }

    /* (d) POSITIVE: cell_mhash with valid small size returns 0. */
    SMALL_PAY[0] = 0x01u8
    SMALL_PAY[1] = 0x02u8
    SMALL_PAY[2] = 0x03u8
    SMALL_PAY[3] = 0x04u8
    SMALL_PAY[4] = 0x05u8
    SMALL_PAY[5] = 0x06u8
    SMALL_PAY[6] = 0x07u8
    SMALL_PAY[7] = 0x08u8
    if xii_emit_gen_cell_mhash(50u32, 1u32, 8u32, &SMALL_PAY as *u8, &MHASH_OUT as *u8) != 0i32 { return 6u64 }
    /* hash output is non-zero (a real SHA-256 of the 12-byte input 50||1||8||payload). */
    let mut all_zero : u8 = 1u8
    let mut z : u32 = 0u32
    while z < 32u32 {
        if MHASH_OUT[z] != 0u8 { all_zero = 0u8 }
        z = z + 1u32
    }
    if all_zero != 0u8 { return 7u64 }

    /* (e) POSITIVE: override with valid (50, 1) returns 0 and resolves. */
    if xii_emit_gen_override(50u8, 1u8, &SMALL_PAY as *u8, 8u16) != 0i32 { return 8u64 }
    if xeg_override_index(50u8, 1u8) == 0xFFFFFFFFu32 { return 9u64 }

    return 99u64
}
